import{_ as n,o as i,c as r,ag as a}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"E-Mail-Integration","description":"","frontmatter":{},"headers":[],"relativePath":"de/settings/email.md","filePath":"de/settings/email.md"}'),t={name:"de/settings/email.md"};function l(o,e,s,d,g,h){return i(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="e-mail-integration" tabindex="-1">E-Mail-Integration <a class="header-anchor" href="#e-mail-integration" aria-label="Permalink to &quot;E-Mail-Integration&quot;">​</a></h1><p>Konfigurieren Sie, wie MyCompanyDesk E-Mails an Ihre Kunden sendet — von der Rechnungszustellung bis zu Zahlungserinnerungen.</p><h2 id="e-mail-versandmethoden" tabindex="-1">E-Mail-Versandmethoden <a class="header-anchor" href="#e-mail-versandmethoden" aria-label="Permalink to &quot;E-Mail-Versandmethoden&quot;">​</a></h2><p>MyCompanyDesk unterstützt drei Wege zum Versenden von E-Mails:</p><h3 id="_1-integrierter-e-mail-versand-standard" tabindex="-1">1. Integrierter E-Mail-Versand (Standard) <a class="header-anchor" href="#_1-integrierter-e-mail-versand-standard" aria-label="Permalink to &quot;1. Integrierter E-Mail-Versand (Standard)&quot;">​</a></h3><p>Standardmäßig werden E-Mails über den eigenen E-Mail-Dienst von MyCompanyDesk versendet. Keine Konfiguration erforderlich.</p><h3 id="_2-gmail-integration" tabindex="-1">2. Gmail-Integration <a class="header-anchor" href="#_2-gmail-integration" aria-label="Permalink to &quot;2. Gmail-Integration&quot;">​</a></h3><p>Senden Sie E-Mails direkt von Ihrem Gmail-Konto:</p><ol><li>Gehen Sie zu <strong>Einstellungen &gt; Kommunikation &gt; E-Mail</strong></li><li>Klicken Sie auf <strong>Gmail verbinden</strong></li><li>Autorisieren Sie MyCompanyDesk, in Ihrem Namen über Google OAuth zu senden</li><li>E-Mails werden jetzt als von Ihrer Gmail-Adresse gesendet angezeigt</li></ol><p><strong>Vorteile:</strong></p><ul><li>E-Mails zeigen Ihre Gmail-Adresse als Absender</li><li>Gesendete E-Mails erscheinen in Ihrem Gmail-Ordner „Gesendet&quot;</li><li>Bessere Zustellbarkeit (Ihre eigene Domain-Reputation)</li></ul><h3 id="_3-outlook-microsoft-integration" tabindex="-1">3. Outlook / Microsoft-Integration <a class="header-anchor" href="#_3-outlook-microsoft-integration" aria-label="Permalink to &quot;3. Outlook / Microsoft-Integration&quot;">​</a></h3><p>Senden Sie von Ihrem Outlook- oder Microsoft 365-Konto:</p><ol><li>Gehen Sie zu <strong>Einstellungen &gt; Kommunikation &gt; E-Mail</strong></li><li>Klicken Sie auf <strong>Outlook verbinden</strong></li><li>Autorisieren Sie über Microsoft OAuth</li><li>E-Mails werden von Ihrer Outlook-Adresse gesendet</li></ol><h3 id="_4-benutzerdefiniertes-smtp" tabindex="-1">4. Benutzerdefiniertes SMTP <a class="header-anchor" href="#_4-benutzerdefiniertes-smtp" aria-label="Permalink to &quot;4. Benutzerdefiniertes SMTP&quot;">​</a></h3><p>Für volle Kontrolle verwenden Sie Ihren eigenen SMTP-Server:</p><ol><li>Gehen Sie zu <strong>Einstellungen &gt; Kommunikation &gt; E-Mail</strong></li><li>Geben Sie Ihre SMTP-Details ein: <ul><li><strong>Host</strong> — SMTP-Serveradresse</li><li><strong>Port</strong> — Server-Port (587 für TLS, 465 für SSL)</li><li><strong>Benutzername</strong> — SMTP-Anmeldung</li><li><strong>Passwort</strong> — SMTP-Passwort</li></ul></li><li>Klicken Sie auf <strong>Verbindung testen</strong>, um die Funktion zu überprüfen</li><li>Speichern</li></ol><h2 id="e-mail-vorlagen" tabindex="-1">E-Mail-Vorlagen <a class="header-anchor" href="#e-mail-vorlagen" aria-label="Permalink to &quot;E-Mail-Vorlagen&quot;">​</a></h2><p>Passen Sie die E-Mails an, die mit Ihren Rechnungen und Erinnerungen versendet werden.</p><h3 id="rechnungs-e-mail-vorlage" tabindex="-1">Rechnungs-E-Mail-Vorlage <a class="header-anchor" href="#rechnungs-e-mail-vorlage" aria-label="Permalink to &quot;Rechnungs-E-Mail-Vorlage&quot;">​</a></h3><p>Die Standard-E-Mail, die beim Versand einer Rechnung gesendet wird. Passen Sie an:</p><ul><li><strong>Betreffzeile</strong> — Der E-Mail-Betreff (unterstützt Variablen wie Rechnungsnummer)</li><li><strong>Text</strong> — Der Nachrichteninhalt</li><li><strong>Sprache</strong> — Sprachspezifische Vorlagen festlegen</li></ul><h3 id="erinnerungs-e-mail-vorlage" tabindex="-1">Erinnerungs-E-Mail-Vorlage <a class="header-anchor" href="#erinnerungs-e-mail-vorlage" aria-label="Permalink to &quot;Erinnerungs-E-Mail-Vorlage&quot;">​</a></h3><p>Die E-Mail, die beim Nachfassen bei überfälligen Rechnungen gesendet wird. Passen Sie die gleichen Felder wie oben an, aber mit einem dringenderen Ton.</p><h3 id="vorschau" tabindex="-1">Vorschau <a class="header-anchor" href="#vorschau" aria-label="Permalink to &quot;Vorschau&quot;">​</a></h3><p>Vor dem Versand können Sie jede E-Mail in der Vorschau ansehen, um genau zu sehen, was Ihr Kunde erhalten wird:</p><ul><li>Gerendertes HTML mit Ihrem Branding</li><li>PDF-Anhang-Vorschau</li><li>Zahlungslink-Einbindung</li></ul><h2 id="variablen" tabindex="-1">Variablen <a class="header-anchor" href="#variablen" aria-label="Permalink to &quot;Variablen&quot;">​</a></h2><p>E-Mail-Vorlagen unterstützen dynamische Variablen:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Beschreibung</th></tr></thead><tbody><tr><td><code>{invoice_number}</code></td><td>Die Rechnungsnummer</td></tr><tr><td><code>{customer_name}</code></td><td>Name des Kunden</td></tr><tr><td><code>{amount}</code></td><td>Gesamtrechnungsbetrag</td></tr><tr><td><code>{due_date}</code></td><td>Fälligkeitsdatum der Zahlung</td></tr><tr><td><code>{company_name}</code></td><td>Ihr Firmenname</td></tr><tr><td><code>{payment_link}</code></td><td>Link zur Online-Zahlung</td></tr></tbody></table><h2 id="benachrichtigungen" tabindex="-1">Benachrichtigungen <a class="header-anchor" href="#benachrichtigungen" aria-label="Permalink to &quot;Benachrichtigungen&quot;">​</a></h2><p>Konfigurieren Sie, welche E-Mail-Benachrichtigungen Sie erhalten:</p><ul><li><strong>Rechnung bezahlt</strong> — Benachrichtigung, wenn ein Kunde zahlt</li><li><strong>Angebotsanfrage eingegangen</strong> — Benachrichtigung bei neuen Angebotsanfragen</li><li><strong>Teamaktivitäten</strong> — Aktualisierungen zu Aktionen von Teammitgliedern</li></ul><p>Benachrichtigungseinstellungen können in Ihrem <a href="/de/account/profile">Profil</a> festgelegt werden.</p><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Verbinden Sie Gmail oder Outlook für die beste Zustellbarkeit</li><li>Testen Sie Ihre E-Mail-Vorlage immer, bevor Sie Ihre erste Rechnung versenden</li><li>Richten Sie sprachspezifische Vorlagen ein, wenn Sie Kunden in mehreren Sprachen bedienen</li><li>Verwenden Sie die Erinnerungsvorlage für professionelle Nachfassaktionen bei überfälligen Rechnungen</li></ul>',36)])])}const m=n(t,[["render",l]]);export{c as __pageData,m as default};
